import React, { useState } from 'react';
import { colorFor, initials, fmtTime, isOnline } from '../data';
import Avatar from './Avatar';
import styles from './Sidebar.module.css';

export default function Sidebar({ currentUser, users, messages, activeContact, onSelectContact, onLogout }) {
  const [search, setSearch] = useState('');

  function getLastMsg(uid) {
    const key = [currentUser.id, uid].sort().join('_');
    const msgs = messages[key] || [];
    return msgs[msgs.length - 1];
  }

  function getUnread(uid) {
    const key = [currentUser.id, uid].sort().join('_');
    return (messages[key] || []).filter(m => m.from === uid && !m.read).length;
  }

  const contacts = users
    .filter(u => u.id !== currentUser.id && u.name.toLowerCase().includes(search.toLowerCase()))
    .sort((a, b) => {
      const la = getLastMsg(a.id), lb = getLastMsg(b.id);
      if (!la && !lb) return 0;
      if (!la) return 1;
      if (!lb) return -1;
      return lb.time - la.time;
    });

  const myColor = colorFor(currentUser.name);

  return (
    <aside className={styles.sidebar}>
      <div className={styles.header}>
        <div className={styles.me}>
          <div className={styles.myAvatar} style={{ background: myColor.bg, color: myColor.text }}>
            {initials(currentUser.name)}
          </div>
          <div className={styles.myInfo}>
            <strong>{currentUser.name}</strong>
            <span className={styles.onlineBadge}>Online</span>
          </div>
        </div>
        <button className={styles.logoutBtn} onClick={onLogout}>Sign out</button>
      </div>

      <div className={styles.searchWrap}>
        <input
          className={styles.searchInput}
          placeholder="🔍  Search conversations..."
          value={search}
          onChange={e => setSearch(e.target.value)}
        />
      </div>

      <div className={styles.sectionLabel}>Messages</div>

      <div className={styles.list}>
        {contacts.map(u => {
          const last = getLastMsg(u.id);
          const unread = getUnread(u.id);
          const online = isOnline(u.id);
          const c = colorFor(u.name);
          const preview = last
            ? (last.from === currentUser.id ? 'You: ' : '') + last.text
            : 'Start chatting';
          const isActive = activeContact && activeContact.id === u.id;

          return (
            <div
              key={u.id}
              className={`${styles.contactItem} ${isActive ? styles.active : ''}`}
              onClick={() => onSelectContact(u)}
            >
              <div className={styles.avatarWrap} style={{ background: c.bg, color: c.text }}>
                {initials(u.name)}
                <span className={`${styles.dot} ${online ? styles.online : styles.offline}`} />
              </div>
              <div className={styles.info}>
                <strong>{u.name}</strong>
                <span>{preview}</span>
              </div>
              <div className={styles.meta}>
                <span className={styles.time}>{last ? fmtTime(last.time) : ''}</span>
                {unread > 0 && <span className={styles.badge}>{unread}</span>}
              </div>
            </div>
          );
        })}
      </div>
    </aside>
  );
}
